package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import org.w3c.dom.HTMLInputElement
import org.w3c.dom.HTMLElement
import kotlin.js.Promise

@JsExport
@JsName("sterilization")
object SterilizationModule {

    fun searchLocations() {
        val query = (window.document.getElementById("sterilization-search") as? HTMLInputElement)?.value ?: ""
        loadLocations(if (query.isNotEmpty()) "/user-sterilization-locations?search=$query" else "/user-sterilization-locations")
    }

    private fun loadLocations(url: String): Promise<dynamic> {
        return ApiModule.fetch(url, js("({method: 'GET'})")).then<dynamic> { locations ->
            renderLocations(locations)
        }
    }

    private fun renderLocations(locations: dynamic) {
        val container = window.document.getElementById("sterilization-container") ?: return
        container.innerHTML = ""
        val locationsArray = if (locations is Array<*>) locations else js("([])")
        for (i in 0 until locationsArray.length) {
            val loc = locationsArray[i]
            val div = window.document.createElement("div")
            div.className = "location-card"
            div.innerHTML = """
                <h3>${loc.asDynamic().name}</h3>
                <p>${loc.asDynamic().address}</p>
                <p>${loc.asDynamic().city}, ${loc.asDynamic().state}</p>
                <p>${loc.asDynamic().phone}</p>
            """.trimIndent()
            container.appendChild(div)
        }
    }

    fun debounce(func: dynamic, wait: Int): dynamic {
        var timeout: dynamic = null
        return js("function() { var args = arguments; var ctx = this; var t = timeout; clearTimeout(t); t = setTimeout(function() { func.apply(ctx, args); }, wait); timeout = t; }")
    }
}
