package com.adoptu.frontend

import kotlinx.browser.window
import kotlin.js.Promise

@JsExport
@JsName("api")
object ApiModule {

    var base: String = "/api"

    fun fetch(path: String, options: dynamic? = null): Promise<dynamic> {
        val opts = options ?: js("({})")
        val headers = opts.asDynamic().headers ?: js("({})")
        if (headers["Content-Type"] == null && headers["content-type"] == null) {
            headers["Content-Type"] = "application/json"
        }
        opts.asDynamic().headers = headers
        return window.fetch("$base$path", opts).then<dynamic> { response ->
            val resp = response.asDynamic()
            if (!resp.ok) {
                resp.text().then<dynamic> { text ->
                    Promise.reject(js("new Error('Request failed: ' + text)"))
                }
            } else {
                val contentType = resp.headers.get("Content-Type")
                if (contentType != null && contentType.contains("application/json")) {
                    resp.json()
                } else {
                    js("({success: true})")
                }
            }
        }
    }

    fun me(): Promise<dynamic> = fetch("/auth/me", js("({method: 'GET'})"))
    fun logout(): Promise<dynamic> = fetch("/auth/logout", js("({method: 'POST'})"))

    fun getPets(type: String?): Promise<dynamic> {
        val url = if (type != null) "/pets?type=$type" else "/pets"
        return fetch(url, js("({method: 'GET'})"))
    }

    fun getPet(id: Int): Promise<dynamic> = fetch("/pets/$id", js("({method: 'GET'})"))
    fun createPet(pet: dynamic): Promise<dynamic> = fetch("/pets", js("({method: 'POST', body: JSON.stringify(pet)})"))
    fun updatePet(id: Int, pet: dynamic): Promise<dynamic> = fetch("/pets/$id", js("({method: 'PUT', body: JSON.stringify(pet)})"))
    fun deletePet(id: Int): Promise<dynamic> = fetch("/pets/$id", js("({method: 'DELETE'})"))

    fun adoptPet(id: Int, message: String?): Promise<dynamic> {
        val body = if (message != null) js("({message: message})") else js("({})")
        return fetch("/pets/$id/adopt", js("({method: 'POST', body: JSON.stringify(body)})"))
    }

    fun addImage(petId: Int, file: dynamic, isPrimary: Boolean): Promise<dynamic> {
        val formData = js("new FormData()")
        formData.append("image", file)
        formData.append("isPrimary", "$isPrimary")
        return fetch("/pets/$petId/images", js("({method: 'POST', body: formData})"))
    }

    fun removeImage(petId: Int, imageId: Int): Promise<dynamic> = fetch("/pets/$petId/images/$imageId", js("({method: 'DELETE'})"))
    fun setPrimaryImage(petId: Int, imageId: Int): Promise<dynamic> = fetch("/pets/$petId/images/$imageId/primary", js("({method: 'PUT'})"))
    fun getAdoptionRequests(petId: Int): Promise<dynamic> = fetch("/pets/$petId/adoption-requests", js("({method: 'GET'})"))
    fun updateAdoptionRequest(requestId: Int, status: String): Promise<dynamic> =
        fetch("/pets/adoption-requests/$requestId", js("({method: 'PUT', body: JSON.stringify({status: status})})"))
    fun getMyAdoptionRequests(): Promise<dynamic> = fetch("/pets/my-adoption-requests", js("({method: 'GET'})"))
    fun getPhotographers(): Promise<dynamic> = fetch("/photographers", js("({method: 'GET'})"))
    fun updateProfile(displayName: String): Promise<dynamic> =
        fetch("/users/profile", js("({method: 'PUT', body: JSON.stringify({displayName: displayName})})"))
    fun updatePhotographerSettings(fee: Int, currency: String, country: String, state: String): Promise<dynamic> =
        fetch("/users/photographer-settings", js("({method: 'PUT', body: JSON.stringify({fee: fee, currency: currency, country: country, state: state})})"))

    fun createPhotographyRequest(photographerId: Int, petId: Int?, message: String): Promise<dynamic> {
        val body: dynamic = js("({})")
        body.photographerId = photographerId
        body.message = message
        if (petId != null) body.petId = petId
        return fetch("/photographers/request", js("({method: 'POST', body: JSON.stringify(body)})"))
    }

    fun createMultiplePhotographyRequests(photographerIds: dynamic, petId: Int?, message: String): Promise<dynamic> {
        val body: dynamic = js("({})")
        body.photographerIds = photographerIds
        body.message = message
        if (petId != null) body.petId = petId
        return fetch("/photographers/requests", js("({method: 'POST', body: JSON.stringify(body)})"))
    }

    fun getPhotographyRequests(): Promise<dynamic> = fetch("/photographers/requests", js("({method: 'GET'})"))

    fun updatePhotographyRequest(requestId: Int, status: String?, scheduledDate: String?): Promise<dynamic> {
        val body: dynamic = js("({})")
        if (status != null) body.status = status
        if (scheduledDate != null) body.scheduledDate = scheduledDate
        return fetch("/photographers/requests/$requestId", js("({method: 'PUT', body: JSON.stringify(body)})"))
    }

    fun activateRescuer(activate: Boolean): Promise<dynamic> =
        fetch("/users/rescuer-profile", js("({method: 'POST', body: JSON.stringify({activate: activate})})"))
    fun activatePhotographer(activate: Boolean): Promise<dynamic> =
        fetch("/users/photographer-profile", js("({method: 'POST', body: JSON.stringify({activate: activate})})"))
    fun activateTemporalHome(activate: Boolean): Promise<dynamic> =
        fetch("/users/temporal-home-profile", js("({method: 'POST', body: JSON.stringify({activate: activate})})"))
    fun createTemporalHome(data: dynamic): Promise<dynamic> =
        fetch("/users/temporal-home", js("({method: 'POST', body: JSON.stringify(data)})"))
    fun updateTemporalHome(data: dynamic): Promise<dynamic> =
        fetch("/users/temporal-home", js("({method: 'PUT', body: JSON.stringify(data)})"))
    fun getTemporalHome(): Promise<dynamic> = fetch("/users/temporal-home", js("({method: 'GET'})"))
    fun getTemporalHomeRequests(): Promise<dynamic> = fetch("/temporal-homes/requests", js("({method: 'GET'})"))
    fun blockRescuer(rescuerId: Int): Promise<dynamic> = fetch("/temporal-homes/block/$rescuerId", js("({method: 'POST'})"))
    fun updateLanguage(language: String): Promise<dynamic> =
        fetch("/users/language", js("({method: 'PUT', body: JSON.stringify({language: language})})"))
    fun hasPassword(): Promise<dynamic> = fetch("/users/has-password", js("({method: 'GET'})"))
    fun setPassword(encryptedPassword: String): Promise<dynamic> =
        fetch("/users/password", js("({method: 'POST', body: JSON.stringify({encryptedPassword: encryptedPassword})})"))
    fun changePassword(encryptedCurrentPassword: String, encryptedNewPassword: String): Promise<dynamic> =
        fetch("/users/password", js("({method: 'PUT', body: JSON.stringify({encryptedCurrentPassword: encryptedCurrentPassword, encryptedNewPassword: encryptedNewPassword})})"))
    fun requestEmailChange(newEmail: String): Promise<dynamic> =
        fetch("/users/request-email-change", js("({method: 'POST', body: JSON.stringify({newEmail: newEmail})})"))
    fun requestMagicLink(encryptedData: String): Promise<dynamic> =
        fetch("/auth/request-magic-link", js("({method: 'POST', body: JSON.stringify({encryptedData: encryptedData})})"))
    fun loginWithPassword(email: String, encryptedPassword: String): Promise<dynamic> =
        fetch("/auth/login-with-password", js("({method: 'POST', body: JSON.stringify({email: email, encryptedPassword: encryptedPassword})})"))
    fun forgotPassword(encryptedData: String): Promise<dynamic> =
        fetch("/auth/forgot-password", js("({method: 'POST', body: JSON.stringify({encryptedData: encryptedData})})"))
    fun resetPassword(token: String, encryptedPassword: String): Promise<dynamic> =
        fetch("/auth/reset-password?token=$token", js("({method: 'POST', body: JSON.stringify({encryptedData: encryptedPassword})})"))
}

fun apiFetch(path: String, method: String = "GET", body: dynamic? = null): Promise<dynamic> {
    val options: dynamic = js("({})")
    options.method = method
    options.headers = js("({'Content-Type': 'application/json'})")
    if (body != null) options.body = js("JSON.stringify(body)")
    return window.fetch(path, options).then<dynamic> { response ->
        val resp = response.asDynamic()
        if (!resp.ok) {
            resp.text().then<dynamic> { text ->
                Promise.reject(js("new Error('Request failed: ' + text)"))
            }
        } else {
            val contentType = resp.headers.get("Content-Type")
            if (contentType != null && contentType.contains("application/json")) {
                resp.json()
            } else {
                js("({success: true})")
            }
        }
    }
}

fun showMessage(elementId: String, message: String) {
    val el = window.document.getElementById(elementId)
    if (el != null) {
        el.textContent = message
    }
}
