package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import org.w3c.dom.HTMLElement
import kotlin.js.Promise

@JsExport
@JsName("petDetail")
object PetDetailModule {
    var petData: dynamic = null

    fun load(): Promise<dynamic> {
        val pathParts = window.location.pathname.split("/")
        val id = pathParts.last().toIntOrNull() ?: return Promise.reject(js("new Error('Invalid pet ID')"))

        return ApiModule.getPet(id).then<dynamic> { pet ->
            petData = pet
            renderPetDetails(pet)
            renderImages()
        }
    }

    private fun renderPetDetails(pet: dynamic) {
        window.document.getElementById("pet-name")?.textContent = pet.asDynamic().name as? String ?: ""
        window.document.getElementById("pet-type")?.textContent = pet.asDynamic().type as? String ?: ""
        window.document.getElementById("pet-breed")?.textContent = pet.asDynamic().breed as? String ?: ""
        window.document.getElementById("pet-age")?.textContent = pet.asDynamic().age?.toString() ?: ""
        window.document.getElementById("pet-sex")?.textContent = pet.asDynamic().sex as? String ?: ""
        window.document.getElementById("pet-description")?.textContent = pet.asDynamic().description as? String ?: ""
    }

    fun renderImages(): String {
        val container = window.document.getElementById("pet-images") ?: return ""
        container.innerHTML = ""

        val images = petData?.asDynamic()?.images ?: js("([])")
        val imagesArray = if (images is Array<*>) images else images

        for (i in 0 until imagesArray.length) {
            val image = imagesArray[i]
            val img = window.document.createElement("img")
            img.asDynamic().src = image.asDynamic().url as String
            img.className = "pet-image"
            if (image.asDynamic().isPrimary == true) {
                img.asDynamic().classList.add("primary")
            }
            container.appendChild(img)
        }

        return container.innerHTML
    }
}
