package com.adoptu.frontend.utils

import com.adoptu.frontend.CryptoModule
import com.adoptu.frontend.RsaCryptoModule
import com.adoptu.frontend.PublicKeyModule

@Deprecated("Use com.adoptu.frontend.RsaCryptoModule instead")
@JsExport
object RsaCrypto {
    fun encrypt(plaintext: String, publicKeyPem: String): dynamic = CryptoModule.encrypt(plaintext, publicKeyPem)
    fun importPublicKey(pemKey: String): dynamic = RsaCryptoModule.importPublicKey(pemKey)
}

@Deprecated("Use com.adoptu.frontend.PublicKeyModule instead")
@JsExport
object PublicKey {
    var cached: dynamic
        get() = PublicKeyModule.cached
        set(value) { PublicKeyModule.cached = value }

    fun get(): dynamic = PublicKeyModule.get()
}
