package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import kotlin.js.Promise

@JsExport
@JsName("petFood")
object PetFoodModule {

    fun showFoodInfo(petType: String): Promise<dynamic> {
        val container = window.document.getElementById("pet-food-info") ?: return Promise.resolve(Unit)
        val content = when (petType.lowercase()) {
            "dog" -> """
                <h3>Dog Food Recommendations</h3>
                <ul>
                    <li>High-quality dry kibble</li>
                    <li>Wet food for hydration</li>
                    <li>Age-appropriate formula (puppy, adult, senior)</li>
                    <li>Portion size based on weight and activity level</li>
                </ul>
            """.trimIndent()
            "cat" -> """
                <h3>Cat Food Recommendations</h3>
                <ul>
                    <li>High-protein wet food</li>
                    <li>Dry kibble for dental health</li>
                    <li>Age-appropriate formula (kitten, adult, senior)</li>
                    <li>Fresh water always available</li>
                </ul>
            """.trimIndent()
            else -> "<p>Select a pet type to see food recommendations.</p>"
        }
        container.innerHTML = content
        return Promise.resolve(Unit)
    }
}
