package com.adoptu.frontend

import com.adoptu.frontend.i18n.I18nModule
import com.adoptu.frontend.i18n.setLang
import kotlinx.browser.window
import org.w3c.dom.HTMLSelectElement
import kotlin.js.Promise

@JsExport
@JsName("Common")
object CommonModule {
    var isLoggedIn: Boolean = false

    fun onCountryChange() {
        val countrySelect = window.document.getElementById("profile-country")
        val stateContainer = window.document.getElementById("state-container")
        if (countrySelect != null && stateContainer != null) {
            val country = (countrySelect as HTMLSelectElement).value
            if (country == "US") {
                stateContainer.asDynamic().style.display = "block"
            } else {
                stateContainer.asDynamic().style.display = "none"
            }
        }
    }

    fun initI18n(userLanguage: String?): Promise<dynamic> {
        val lang = userLanguage ?: window.localStorage.getItem("preferredLanguage") ?: "en"
        return I18nModule.loadLang(lang).then<dynamic> {
            I18nModule.updatePage()
            I18nModule.updateActiveLangOption()
        }
    }

    fun checkProfileCompletion(user: dynamic): dynamic {
        val hasProfile = user.asDynamic().displayName != null && (user.asDynamic().displayName as String).isNotEmpty()
        val hasCountry = user.asDynamic().country != null && (user.asDynamic().country as String).isNotEmpty()
        return js("({hasProfile: hasProfile, hasCountry: hasCountry})")
    }

    fun getUserDataPromise(): dynamic = window.asDynamic().userDataPromise
    fun getCachedUserData(): dynamic? = window.asDynamic().cachedUserData
}
