package com.adoptu.frontend

import kotlinx.browser.window
import org.khronos.webgl.ArrayBuffer
import org.khronos.webgl.Uint8Array
import org.w3c.dom.HTMLElement
import kotlin.js.Promise

@JsExport
@JsName("webauthn")
object WebAuthnModule {

    fun register(email: String, displayName: String, roles: Array<String>, temporalHomeProfile: dynamic? = null): Promise<dynamic> {
        return getRegistrationOptions(email, displayName)
            .then<dynamic> { options ->
                val publicKey = parseCreationOptions(options)
                navigatorCredentialsCreate(publicKey)
            }
            .then<dynamic> { credential ->
                val credentialJson = toJSON(credential)
                val body: dynamic = js("({})")
                body.email = email
                body.displayName = displayName
                body.registrationResponse = credentialJson
                if (roles.isNotEmpty()) body.roles = roles
                if (temporalHomeProfile != null) body.temporalHomeProfile = temporalHomeProfile
                apiFetch("/api/auth/register", "POST", body)
            }
            .then<dynamic> { result ->
                if (result.success == true) {
                    window.location.href = "/"
                }
                result
            }
            .catch<dynamic> { error ->
                showMessage("passkey-message", "Registration failed: ${error.asDynamic().message}")
                Promise.reject(error)
            }
    }

    private fun getRegistrationOptions(email: String, displayName: String): Promise<dynamic> {
        return apiFetch("/api/auth/registration-options", "POST", js("({email: email, displayName: displayName})"))
    }

    fun authenticate(): Promise<dynamic> {
        return getAssertionOptions()
            .then<dynamic> { options ->
                val publicKey = parseRequestOptions(options)
                navigatorCredentialsGet(publicKey)
            }
            .then<dynamic> { credential ->
                val credentialJson = toJSON(credential)
                val body: dynamic = js("({})")
                body.authenticationResponse = credentialJson
                apiFetch("/api/auth/authenticate", "POST", body)
            }
            .then<dynamic> { result ->
                if (result.success == true) {
                    window.location.href = "/"
                }
                result
            }
            .catch<dynamic> { error ->
                showMessage("passkey-message", "Authentication failed: ${error.asDynamic().message}")
                Promise.reject(error)
            }
    }

    fun authenticateWithResponse(): Promise<dynamic> = authenticate()

    private fun getAssertionOptions(): Promise<dynamic> {
        return apiFetch("/api/auth/assertion-options", "GET")
    }

    fun parseCreationOptions(opts: dynamic): dynamic {
        val publicKey: dynamic = js("({})")
        publicKey.rp = opts.rp
        val user: dynamic = js("({})")
        user.id = base64ToArray(base64UrlToBase64(opts.user.id))
        user.name = opts.user.name
        user.displayName = opts.user.displayName
        publicKey.user = user
        publicKey.challenge = base64ToArray(base64UrlToBase64(opts.challenge))
        publicKey.pubKeyCredParams = opts.pubKeyCredParams
        if (opts.timeout != null) publicKey.timeout = opts.timeout
        if (opts.excludeCredentials != null) {
            val excludeCredentials: dynamic = js("([])")
            for (i in 0 until opts.excludeCredentials.length) {
                val cred: dynamic = js("({})")
                cred.id = base64ToArray(base64UrlToBase64(opts.excludeCredentials[i].id))
                cred.type = opts.excludeCredentials[i].type
                excludeCredentials.push(cred)
            }
            publicKey.excludeCredentials = excludeCredentials
        }
        if (opts.authenticatorSelection != null) publicKey.authenticatorSelection = opts.authenticatorSelection
        if (opts.attestation != null) publicKey.attestation = opts.attestation
        if (opts.extensions != null) publicKey.extensions = opts.extensions
        return publicKey
    }

    fun parseRequestOptions(opts: dynamic): dynamic {
        val publicKey: dynamic = js("({})")
        if (opts.challenge != null) {
            publicKey.challenge = base64ToArray(base64UrlToBase64(opts.challenge))
        }
        if (opts.timeout != null) publicKey.timeout = opts.timeout
        if (opts.rpId != null) publicKey.rpId = opts.rpId
        if (opts.allowCredentials != null) {
            val allowCredentials: dynamic = js("([])")
            for (i in 0 until opts.allowCredentials.length) {
                val cred: dynamic = js("({})")
                cred.id = base64ToArray(base64UrlToBase64(opts.allowCredentials[i].id))
                cred.type = opts.allowCredentials[i].type
                if (opts.allowCredentials[i].transports != null) cred.transports = opts.allowCredentials[i].transports
                allowCredentials.push(cred)
            }
            publicKey.allowCredentials = allowCredentials
        }
        if (opts.extensions != null) publicKey.extensions = opts.extensions
        return publicKey
    }

    fun base64ToArray(base64: String): ArrayBuffer {
        val binaryString = window.atob(base64)
        val bytes = Uint8Array(binaryString.length)
        for (i in 0 until binaryString.length) {
            js("bytes[i] = binaryString.charCodeAt(i)")
        }
        return bytes.buffer
    }

    fun base64UrlToBase64(base64url: String): String {
        return base64url.replace('-', '+').replace('_', '/')
    }

    fun arrayToBase64(arr: ArrayBuffer): String {
        val bytes = Uint8Array(arr)
        var binaryString = ""
        for (i in 0 until bytes.length) {
            binaryString += js("String.fromCharCode(bytes[i])")
        }
        return window.btoa(binaryString)
    }

    fun toJSON(cred: dynamic): dynamic {
        val result: dynamic = js("({})")
        result.id = cred.id
        result.type = cred.type
        result.rawId = arrayToBase64(cred.rawId)

        val response: dynamic = js("({})")
        val credResponse = cred.response

        if (credResponse.clientDataJSON != null) response.clientDataJSON = arrayToBase64(credResponse.clientDataJSON)
        if (credResponse.attestationObject != null) response.attestationObject = arrayToBase64(credResponse.attestationObject)
        if (credResponse.authenticatorData != null) response.authenticatorData = arrayToBase64(credResponse.authenticatorData)
        if (credResponse.signature != null) response.signature = arrayToBase64(credResponse.signature)
        if (credResponse.userHandle != null) response.userHandle = arrayToBase64(credResponse.userHandle)
        if (credResponse.publicKeyAlgorithm != null) response.publicKeyAlgorithm = credResponse.publicKeyAlgorithm
        if (credResponse.publicKey != null) response.publicKey = arrayToBase64(credResponse.publicKey)

        result.response = response
        return result
    }

    private fun navigatorCredentialsCreate(publicKey: dynamic): Promise<dynamic> {
        return Promise { resolve: dynamic, reject: dynamic ->
            try {
                val credentials = window.asDynamic().navigator.credentials
                credentials.create(js("({publicKey: publicKey})")).then(
                    { value: dynamic -> resolve(value) },
                    { reason: dynamic -> reject(reason) }
                )
            } catch (e: Throwable) {
                reject(e)
            }
        }
    }

    private fun navigatorCredentialsGet(publicKey: dynamic): Promise<dynamic> {
        return Promise { resolve: dynamic, reject: dynamic ->
            try {
                val credentials = window.asDynamic().navigator.credentials
                credentials.get(js("({publicKey: publicKey})")).then(
                    { value: dynamic -> resolve(value) },
                    { reason: dynamic -> reject(reason) }
                )
            } catch (e: Throwable) {
                reject(e)
            }
        }
    }
}
