package com.adoptu.frontend

import kotlinx.browser.window
import org.khronos.webgl.ArrayBuffer
import org.khronos.webgl.Uint8Array
import kotlin.js.Promise

@JsExport
@JsName("rsaCrypto")
object RsaCryptoModule {

    fun encrypt(plaintext: String, publicKeyPem: String): Promise<String> {
        return importPublicKey(publicKeyPem).then<dynamic> { publicKey ->
            val encoder = js("new TextEncoder()")
            val data: ArrayBuffer = encoder.encode(plaintext)
            window.asDynamic().crypto.subtle.encrypt(
                js("({name: 'RSA-OAEP'})"),
                publicKey,
                data
            )
        }.then<dynamic> { encrypted ->
            arrayToBase64Url(encrypted)
        }
    }

    fun importPublicKey(pemKey: String): Promise<dynamic> {
        val base64 = pemKey
            .replace("-----BEGIN PUBLIC KEY-----", "")
            .replace("-----END PUBLIC KEY-----", "")
            .replace("\n", "")
            .replace("\r", "")
        val binary = window.atob(base64)
        val bytes = Uint8Array(binary.length)
        for (i in 0 until binary.length) {
            js("bytes[i] = binary.charCodeAt(i)")
        }
        return window.asDynamic().crypto.subtle.importKey(
            js("({name: 'RSA-OAEP'})"),
            bytes.buffer,
            js("({name: 'RSA-OAEP'})"),
            true,
            js("({encrypt: true})")
        )
    }
}

@JsExport
@JsName("getPublicKey")
fun getPublicKey(): Promise<String> {
    return apiFetch("/api/auth/encryption-key", "GET").then<dynamic> { data ->
        data.asDynamic().publicKey as String
    }
}

@JsExport
@JsName("Crypto")
object CryptoModule {
    fun encrypt(plaintext: String, publicKeyPem: String): Promise<String> = RsaCryptoModule.encrypt(plaintext, publicKeyPem)
    fun getPublicKey(): Promise<String> = com.adoptu.frontend.getPublicKey()
}

@JsExport
@JsName("PublicKey")
object PublicKeyModule {
    var cached: dynamic = null

    fun get(): Promise<dynamic> {
        if (cached != null) return Promise.resolve(cached)
        return com.adoptu.frontend.getPublicKey().then<dynamic> { pemKey ->
            RsaCryptoModule.importPublicKey(pemKey)
        }.then<dynamic> { key ->
            cached = key
            key
        }
    }
}

fun arrayToBase64Url(buffer: ArrayBuffer): String {
    val bytes = Uint8Array(buffer)
    var binary = ""
    for (i in 0 until bytes.length) {
        binary += js("String.fromCharCode(bytes[i])")
    }
    return window.btoa(binary)
        .replace('+', '-')
        .replace('/', '_')
        .replace("=", "")
}
