package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import com.adoptu.frontend.i18n.I18nModule
import com.adoptu.frontend.i18n.setLang
import kotlinx.browser.window
import org.w3c.dom.HTMLButtonElement
import org.w3c.dom.HTMLInputElement
import org.w3c.dom.HTMLSelectElement
import org.w3c.dom.HTMLElement
import kotlin.js.Promise

@JsExport
@JsName("profile")
object ProfileModule {

    fun load(): Promise<dynamic> {
        return ApiModule.me().then<dynamic> { user ->
            val displayNameInput = window.document.getElementById("profile-displayName") as? HTMLInputElement
            val emailDisplay = window.document.getElementById("profile-email") as? HTMLElement

            displayNameInput?.value = user.asDynamic().displayName as? String ?: ""
            emailDisplay?.textContent = user.asDynamic().email as? String ?: ""

            val countrySelect = window.document.getElementById("profile-country") as? HTMLSelectElement
            if (countrySelect != null && user.asDynamic().country != null) {
                countrySelect.value = user.asDynamic().country as String
            }

            CommonModule.onCountryChange()
            user
        }.catch<dynamic> {
            window.location.href = "/login"
        }
    }

    fun setupSaveButton() {
        val saveBtn = window.document.getElementById("profile-save-btn") as? HTMLButtonElement
        saveBtn?.addEventListener("click", {
            val displayName = (window.document.getElementById("profile-displayName") as? HTMLInputElement)?.value ?: ""
            ApiModule.updateProfile(displayName).then<dynamic> {
                showMessage("profile-message", "Profile updated successfully")
            }
        })
    }

    fun setupPasswordButton() {
        val passwordBtn = window.document.getElementById("profile-set-password-btn") as? HTMLButtonElement
        passwordBtn?.addEventListener("click", {
            val passwordInput = window.document.getElementById("profile-new-password") as? HTMLInputElement
            val password = passwordInput?.value ?: ""

            if (!RegisterModule.validatePassword(password)) {
                showMessage("profile-password-message", "Password must be at least 8 characters with uppercase, lowercase, and a number")
                return@addEventListener
            }

            getPublicKey().then<dynamic> { publicKey ->
                RsaCryptoModule.encrypt(password, publicKey)
            }.then<dynamic> { encryptedPassword ->
                ApiModule.setPassword(encryptedPassword)
            }.then<dynamic> {
                showMessage("profile-password-message", "Password set successfully")
            }.catch<dynamic> { error ->
                showMessage("profile-password-message", "Failed to set password: ${error.asDynamic().message}")
            }
        })
    }

    fun setupEmailChangeButton() {
        val emailChangeBtn = window.document.getElementById("profile-change-email-btn") as? HTMLButtonElement
        emailChangeBtn?.addEventListener("click", {
            val newEmail = (window.document.getElementById("profile-new-email") as? HTMLInputElement)?.value ?: ""
            if (newEmail.isEmpty()) {
                showMessage("profile-email-message", "Please enter a new email")
                return@addEventListener
            }
            ApiModule.requestEmailChange(newEmail).then<dynamic> {
                showMessage("profile-email-message", "Verification email sent to $newEmail")
            }.catch<dynamic> { error ->
                showMessage("profile-email-message", "Failed to request email change: ${error.asDynamic().message}")
            }
        })
    }

    fun setupPasskeyButton() {
        val passkeyBtn = window.document.getElementById("profile-add-passkey-btn") as? HTMLButtonElement
        passkeyBtn?.addEventListener("click", {
            ApiModule.me().then<dynamic> { user ->
                val email = user.asDynamic().email as String
                val displayName = user.asDynamic().displayName as String
                WebAuthnModule.register(email, displayName, arrayOf())
            }
        })
    }

    fun setupLanguageSelector() {
        val langSelect = window.document.getElementById("lang-select") as? HTMLSelectElement
        langSelect?.addEventListener("change", {
            val lang = langSelect.value
            setLang(lang)
        })
    }

    fun init(): Promise<dynamic> {
        return load().then<dynamic> {
            setupSaveButton()
            setupPasswordButton()
            setupEmailChangeButton()
            setupPasskeyButton()
            setupLanguageSelector()
        }
    }
}
