package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import com.adoptu.frontend.i18n.I18nModule
import kotlinx.browser.window
import org.w3c.dom.HTMLFormElement
import org.w3c.dom.HTMLInputElement
import org.w3c.dom.HTMLTextAreaElement
import org.w3c.dom.HTMLSelectElement
import kotlin.js.Promise

@JsExport
@JsName("register")
object RegisterModule {

    fun validatePassword(password: String): Boolean {
        return password.length >= 8 &&
            password.any { it.isUpperCase() } &&
            password.any { it.isLowerCase() } &&
            password.any { it.isDigit() }
    }

    fun init(): Promise<dynamic> {
        val form = window.document.getElementById("register-form") as? HTMLFormElement

        form?.addEventListener("submit", { event ->
            event.preventDefault()
            handleRegistration()
        })

        return Promise.resolve(Unit)
    }

    private fun handleRegistration() {
        val passwordInput = window.document.getElementById("register-password") as? HTMLInputElement
        val confirmPasswordInput = window.document.getElementById("register-confirm-password") as? HTMLInputElement
        val password = passwordInput?.value ?: ""
        val confirmPassword = confirmPasswordInput?.value ?: ""

        if (!validatePassword(password)) {
            showMessage("register-message", "Password must be at least 8 characters with uppercase, lowercase, and a number")
            return
        }
        if (password != confirmPassword) {
            showMessage("register-message", "Passwords do not match")
            return
        }

        val emailInput = window.document.getElementById("register-email") as? HTMLInputElement
        val displayNameInput = window.document.getElementById("register-displayName") as? HTMLInputElement
        val email = emailInput?.value ?: ""
        val displayName = displayNameInput?.value ?: ""

        val rolesArray: dynamic = js("([])")
        val adopterCheckbox = window.document.getElementById("role-adopter") as? HTMLInputElement
        if (adopterCheckbox?.checked == true) {
            rolesArray.push("ADOPTER")
        }

        var temporalHomeProfile: dynamic = null
        val temporalHomeCheckbox = window.document.getElementById("role-temporal-home") as? HTMLInputElement
        if (temporalHomeCheckbox?.checked == true) {
            rolesArray.push("TEMPORAL_HOME")
            val thData = getTemporalHomeFormData()
            if (thData != null) {
                temporalHomeProfile = thData
            }
        }

        val roles = js("Array.from(rolesArray)")

        WebAuthnModule.register(email, displayName, roles, temporalHomeProfile)
    }

    private fun getTemporalHomeFormData(): dynamic {
        val availableFrom = (window.document.getElementById("th-available-from") as? HTMLInputElement)?.value
        val availableTo = (window.document.getElementById("th-available-to") as? HTMLInputElement)?.value
        val maxPets = (window.document.getElementById("th-max-pets") as? HTMLInputElement)?.value
        val description = (window.document.getElementById("th-description") as? HTMLTextAreaElement)?.value

        return if (availableFrom != null && availableTo != null) {
            js("({availableFrom: availableFrom, availableTo: availableTo, maxPets: parseInt(maxPets) || 1, description: description || ''})")
        } else {
            null
        }
    }
}
