package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import org.w3c.dom.HTMLInputElement
import org.w3c.dom.HTMLElement
import kotlin.js.Promise

@JsExport
@JsName("shelters")
object SheltersModule {

    fun searchShelters() {
        val query = (window.document.getElementById("shelter-search") as? HTMLInputElement)?.value ?: ""
        loadShelters(if (query.isNotEmpty()) "/user-shelters?search=$query" else "/user-shelters")
    }

    private fun loadShelters(url: String): Promise<dynamic> {
        return ApiModule.fetch(url, js("({method: 'GET'})")).then<dynamic> { shelters ->
            renderShelters(shelters)
        }
    }

    private fun renderShelters(shelters: dynamic) {
        val container = window.document.getElementById("shelters-container") ?: return
        container.innerHTML = ""
        val sheltersArray = if (shelters is Array<*>) shelters else js("([])")
        for (i in 0 until sheltersArray.length) {
            val s = sheltersArray[i]
            val div = window.document.createElement("div")
            div.className = "shelter-card"
            div.innerHTML = """
                <h3>${s.asDynamic().name}</h3>
                <p>${s.asDynamic().city}, ${s.asDynamic().state}</p>
                <p>${s.asDynamic().description}</p>
            """.trimIndent()
            container.appendChild(div)
        }
    }

    fun debounce(func: dynamic, wait: Int): dynamic {
        var timeout: dynamic = null
        return js("function() { var args = arguments; var ctx = this; var t = timeout; clearTimeout(t); t = setTimeout(function() { func.apply(ctx, args); }, wait); timeout = t; }")
    }
}
