package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import org.w3c.dom.HTMLElement
import kotlin.js.Promise

@JsExport
@JsName("Index")
object IndexModule {
    var currentType: String = ""
    var currentSex: String = ""

    fun loadPets(): Promise<dynamic> {
        val type = if (currentType.isNotEmpty()) currentType else null
        return ApiModule.getPets(type).then<dynamic> { pets ->
            renderPets(pets)
            pets
        }
    }

    private fun renderPets(pets: dynamic) {
        val container = window.document.getElementById("pets-container") ?: return
        container.innerHTML = ""

        val petsArray = if (pets is Array<*>) pets else js("([])")
        for (i in 0 until petsArray.length) {
            val pet = petsArray[i]
            val card = window.document.createElement("div")
            card.className = "pet-card"
            val link = window.document.createElement("a")
            link.setAttribute("href", "/pets/${pet.asDynamic().id}")
            val img = window.document.createElement("img")
            img.asDynamic().src = pet.asDynamic().primaryImageUrl ?: "/static/images/placeholder.png"
            img.setAttribute("alt", pet.asDynamic().name as? String ?: "")
            val h3 = window.document.createElement("h3")
            h3.textContent = pet.asDynamic().name as? String ?: ""
            val p = window.document.createElement("p")
            p.textContent = "${pet.asDynamic().type} - ${pet.asDynamic().breed}"
            link.appendChild(img)
            link.appendChild(h3)
            link.appendChild(p)
            card.appendChild(link)
            container.appendChild(card)
        }
    }
}
