package com.adoptu.frontend.utils

import com.adoptu.frontend.WebAuthnModule

@Deprecated("Use com.adoptu.frontend.WebAuthnModule instead")
@JsExport
object WebAuthn {
    fun register(email: String, displayName: String, roles: Array<String>, temporalHomeProfile: dynamic = null): dynamic =
        WebAuthnModule.register(email, displayName, roles, temporalHomeProfile)
    fun authenticate(): dynamic = WebAuthnModule.authenticate()
    fun authenticateWithResponse(): dynamic = WebAuthnModule.authenticateWithResponse()
    fun parseCreationOptions(opts: dynamic): dynamic = WebAuthnModule.parseCreationOptions(opts)
    fun parseRequestOptions(opts: dynamic): dynamic = WebAuthnModule.parseRequestOptions(opts)
    fun base64ToArray(base64: String): dynamic = WebAuthnModule.base64ToArray(base64)
    fun base64UrlToBase64(base64url: String): dynamic = WebAuthnModule.base64UrlToBase64(base64url)
    fun arrayToBase64(arr: dynamic): dynamic = WebAuthnModule.arrayToBase64(arr)
    fun toJSON(cred: dynamic): dynamic = WebAuthnModule.toJSON(cred)
}
