package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import kotlin.js.Promise

@JsExport
@JsName("temporalHome")
object TemporalHomeModule {

    fun blockRescuerAndRedirect(thId: Int, rId: Int): Promise<Unit> {
        return ApiModule.blockRescuer(rId).then<dynamic> {
            window.location.href = "/temporal-homes"
        }.catch<dynamic> { error ->
            showMessage("temporal-home-message", "Failed to block rescuer: ${error.asDynamic().message as String}")
        }
    }
}
