package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import kotlin.js.Promise

@JsExport
@JsName("profilePage")
object ProfilePageModule {
    fun load() = ProfileModule.load()

    fun loadPhotographer(): Promise<dynamic> {
        return ApiModule.getTemporalHome().then<dynamic> { response ->
            if (response != null) response else js("null")
        }
    }

    fun loadTemporalHome(): Promise<dynamic> {
        return ApiModule.getTemporalHome().then<dynamic> { response ->
            if (response != null) response else js("null")
        }
    }

    fun loadShelter(): Promise<dynamic> {
        return ApiModule.fetch("/users/shelter", js("({method: 'GET'})")).then<dynamic> { response ->
            if (response != null) response else js("null")
        }
    }

    fun loadSterilization(): Promise<dynamic> {
        return ApiModule.fetch("/users/sterilization-location", js("({method: 'GET'})")).then<dynamic> { response ->
            if (response != null) response else js("null")
        }
    }

    fun loadPasswordStatus(): Promise<dynamic> {
        return ApiModule.hasPassword().catch<dynamic> { js("({hasPassword: false})") }
    }

    fun loadPasskeyStatus(): Promise<dynamic> {
        return ApiModule.fetch("/auth/has-passkey", js("({method: 'GET'})")).catch<dynamic> { js("({hasPasskey: false})") }
    }
}
