package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import kotlin.js.Promise

@JsExport
@JsName("temporalHomeProfile")
object TemporalHomeProfileModule {

    fun loadRequests(): Promise<dynamic> {
        return ApiModule.getTemporalHomeRequests().then<dynamic> { reqs ->
            renderRequests(reqs)
        }
    }

    private fun renderRequests(reqs: dynamic) {
        val container = window.document.getElementById("temporal-home-requests-container") ?: return
        container.innerHTML = ""
        val reqsArray = if (reqs is Array<*>) reqs else js("([])")
        for (i in 0 until reqsArray.length) {
            val req = reqsArray[i]
            val div = window.document.createElement("div")
            div.className = "request-item"
            val h3 = window.document.createElement("h3")
            h3.textContent = req.asDynamic().rescuerName as? String
            val p = window.document.createElement("p")
            p.textContent = req.asDynamic().petName as? String
            val btn = window.document.createElement("button")
            btn.textContent = "Block Rescuer"
            btn.addEventListener("click", { blockRescuer(req.asDynamic().rescuerId as Int) })
            div.appendChild(h3)
            div.appendChild(p)
            div.appendChild(btn)
            container.appendChild(div)
        }
    }

    fun blockRescuer(rescuerId: Int): Promise<dynamic> {
        return ApiModule.blockRescuer(rescuerId).then<dynamic> { loadRequests() }
            .catch<dynamic> { error ->
                showMessage("temporal-home-message", "Failed to block rescuer: ${error.asDynamic().message as String}")
            }
    }
}
