package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import kotlin.js.Promise

@JsExport
@JsName("emailChangeVerification")
object EmailChangeVerificationModule {

    fun checkEmailChange(): Promise<dynamic> {
        val params = js("new URLSearchParams(window.location.search)")
        val token = params.get("token") as? String

        if (token != null && token.isNotEmpty()) {
            return window.fetch("/api/users/verify-email-change?token=$token", js("({method: 'GET'})")).then<dynamic> { response ->
                val resp = response.asDynamic()
                if (resp.ok) {
                    resp.json().then<dynamic> {
                        showMessage("email-change-message", "Email changed successfully")
                        window.setTimeout({ window.location.href = "/profile" }, 2000)
                    }
                } else {
                    resp.text().then<dynamic> { text ->
                        showMessage("email-change-message", "Failed to change email: $text")
                    }
                }
            }
        }
        return Promise.resolve(Unit)
    }
}
