package com.adoptu.frontend.pages

import com.adoptu.frontend.pages.LoginModule

@JsExport
@JsName("loginPage")
object LoginPageModule {
    var pendingEmail: String
        get() = LoginModule.pendingEmail
        set(value) { LoginModule.pendingEmail = value }

    fun updateLangButton() = LoginModule.updateLangButton()
    fun checkProfileCompletion(user: dynamic) = LoginModule.checkProfileCompletion(user)
    fun showResendButton() = LoginModule.showResendButton()
}
