package com.adoptu.frontend.i18n

import kotlinx.browser.window
import org.w3c.dom.HTMLElement
import org.w3c.dom.HTMLSelectElement
import org.w3c.dom.NodeList
import kotlin.js.Promise

@JsExport
@JsName("i18n")
object I18nModule {
    var currentLang: String = "en"
    var translations: dynamic = js("({})")
    var loadedLangs: dynamic = js("({})")

    fun loadLang(lang: String): Promise<dynamic> {
        if (loadedLangs[lang] == true) {
            return Promise.resolve(translations)
        }
        return window.fetch("/static/js/i18n/$lang.json", js("({method: 'GET'})")).then<dynamic> { response ->
            val resp = response.asDynamic()
            if (resp.ok) resp.json() else js("({})")
        }.then<dynamic> { langTranslations ->
            translations = langTranslations
            loadedLangs[lang] = true
            currentLang = lang
            translations
        }
    }

    fun t(key: String): String {
        val value = translations.asDynamic()[key]
        return if (value != null) value as String else key
    }

    fun setLang(lang: String, persist: Boolean = true): Promise<dynamic> {
        return loadLang(lang).then<dynamic> {
            updatePage()
            updateActiveLangOption()
            if (persist) {
                window.localStorage.setItem("preferredLanguage", lang)
            }
        }
    }

    fun updatePage() {
        val elements = window.document.querySelectorAll("[data-i18n]")
        for (i in 0 until elements.length) {
            val el = elements.item(i) as HTMLElement
            val key = el.getAttribute("data-i18n")
            if (key != null) {
                val text = t(key)
                if (el.tagName == "INPUT" || el.tagName == "TEXTAREA") {
                    el.setAttribute("placeholder", text)
                } else {
                    el.textContent = text
                }
            }
        }
        sortCountryOptions()
        updateDropdownLabel()
    }

    fun updateActiveLangOption() {
        val langSelect = window.document.getElementById("lang-select") as? HTMLSelectElement
        if (langSelect != null) {
            langSelect.value = currentLang
        }
    }

    fun sortCountryOptions() {
        val countrySelect = window.document.getElementById("profile-country") as? HTMLSelectElement
        if (countrySelect != null) {
            val options = countrySelect.options
            val sorted: dynamic = js("([])")
            for (i in 0 until options.length) {
                sorted.push(options.item(i))
            }
            sorted.sort { a: dynamic, b: dynamic -> a.asDynamic().text.localeCompare(b.asDynamic().text) }
            for (i in 0 until sorted.length) {
                countrySelect.add(sorted[i])
            }
        }
    }

    fun updateDropdownLabel() {
        val langSelect = window.document.getElementById("lang-select") as? HTMLSelectElement
        if (langSelect != null) {
            val selectedOption = langSelect.options.item(langSelect.selectedIndex)
            if (selectedOption != null) {
                val label = window.document.getElementById("lang-label")
                if (label != null) {
                    label.textContent = selectedOption.asDynamic().textContent as? String
                }
            }
        }
    }
}

@JsExport
fun t(key: String): String = I18nModule.t(key)

@JsExport
fun setLang(lang: String) = I18nModule.setLang(lang)
