package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import org.w3c.dom.HTMLButtonElement
import org.w3c.dom.HTMLInputElement
import org.w3c.dom.HTMLTextAreaElement
import org.w3c.dom.HTMLElement
import kotlin.js.Promise

@JsExport
@JsName("photographers")
object PhotographersModule {

    fun searchPhotographers() {
        val query = (window.document.getElementById("photographer-search") as? HTMLInputElement)?.value ?: ""
        loadPhotographers(if (query.isNotEmpty()) "/photographers?search=$query" else "/photographers")
    }

    fun loadPhotographers(url: String): Promise<dynamic> {
        return ApiModule.getPhotographers().then<dynamic> { photographers ->
            renderPhotographers(photographers)
        }
    }

    private fun renderPhotographers(photographers: dynamic) {
        val container = window.document.getElementById("photographers-container") ?: return
        container.innerHTML = ""
        val photographersArray = if (photographers is Array<*>) photographers else js("([])")
        for (i in 0 until photographersArray.length) {
            val p = photographersArray[i]
            val div = window.document.createElement("div")
            div.className = "photographer-card"
            div.innerHTML = """
                <h3>${p.asDynamic().displayName}</h3>
                <p>Fee: ${p.asDynamic().fee} ${p.asDynamic().currency}</p>
                <p>Location: ${p.asDynamic().country}, ${p.asDynamic().state}</p>
                <button class="request-photography-btn">Request Photography</button>
            """.trimIndent()
            val btn = div.querySelector(".request-photography-btn")
            btn?.addEventListener("click", {
                showRequestModal(p.asDynamic().id as Int, p.asDynamic().displayName as String, p.asDynamic().fee.toString())
            })
            container.appendChild(div)
        }
    }

    fun createRequestModal() {
        window.document.getElementById("photography-request-modal")?.asDynamic()?.style?.display = "block"
    }

    fun showRequestModal(photographerId: Int, photographerName: String, fee: String) {
        createRequestModal()
        window.document.getElementById("modal-photographer-name")?.textContent = photographerName
        window.document.getElementById("modal-fee")?.textContent = fee

        val submitBtn = window.document.getElementById("submit-photography-request") as? HTMLButtonElement
        submitBtn?.addEventListener("click", {
            val message = (window.document.getElementById("photography-message") as? HTMLTextAreaElement)?.value ?: ""
            ApiModule.createPhotographyRequest(photographerId, null, message).then<dynamic> {
                showMessage("photography-request-message", "Request sent successfully")
                window.document.getElementById("photography-request-modal")?.asDynamic()?.style?.display = "none"
            }.catch<dynamic> { error ->
                showMessage("photography-request-message", "Failed to send request: ${error.asDynamic().message}")
            }
        })
    }

    fun debounce(func: dynamic, wait: Int): dynamic {
        var timeout: dynamic = null
        return js("function() { var args = arguments; var ctx = this; var t = timeout; clearTimeout(t); t = setTimeout(function() { func.apply(ctx, args); }, wait); timeout = t; }")
    }
}
