package com.adoptu.frontend.utils

import com.adoptu.frontend.CommonModule
import kotlinx.browser.window

@Deprecated("Use com.adoptu.frontend.CommonModule instead")
@JsExport
object Common {
    fun onCountryChange() = CommonModule.onCountryChange()
    fun setLang(lang: String) = com.adoptu.frontend.i18n.setLang(lang)
    fun initI18n(userLanguage: String?) = CommonModule.initI18n(userLanguage)
    fun checkProfileCompletion(user: dynamic) = CommonModule.checkProfileCompletion(user)
    fun getUserDataPromise(): dynamic = CommonModule.getUserDataPromise()
    fun getCachedUserData(): dynamic? = CommonModule.getCachedUserData()
    fun setCachedUserData(value: dynamic) {
        window.asDynamic().cachedUserData = value
    }
}
