package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import org.w3c.dom.HTMLInputElement
import kotlin.js.Promise

@JsExport
@JsName("temporalHomeSearch")
object TemporalHomeSearchModule {

    fun searchTemporalHomes() {
        val query = (window.document.getElementById("temporal-home-search") as? HTMLInputElement)?.value ?: ""
        loadTemporalHomes(if (query.isNotEmpty()) "/temporal-homes?search=$query" else "/temporal-homes")
    }

    private fun loadTemporalHomes(url: String): Promise<dynamic> {
        return ApiModule.fetch(url, js("({method: 'GET'})")).then<dynamic> { homes ->
            displayResults(homes)
        }
    }

    fun displayResults(homes: dynamic) {
        val container = window.document.getElementById("temporal-homes-container") ?: return
        container.innerHTML = ""
        val homesArray = if (homes is Array<*>) homes else js("([])")
        for (i in 0 until homesArray.length) {
            val home = homesArray[i]
            val div = window.document.createElement("div")
            div.className = "temporal-home-card"
            val h3 = window.document.createElement("h3")
            h3.textContent = home.asDynamic().displayName as? String
            val p1 = window.document.createElement("p")
            p1.textContent = "Available: ${home.asDynamic().availableFrom} to ${home.asDynamic().availableTo}"
            val p2 = window.document.createElement("p")
            p2.textContent = "Max pets: ${home.asDynamic().maxPets}"
            val p3 = window.document.createElement("p")
            p3.textContent = home.asDynamic().description as? String
            div.appendChild(h3)
            div.appendChild(p1)
            div.appendChild(p2)
            div.appendChild(p3)
            container.appendChild(div)
        }
    }

    fun debounce(func: dynamic, wait: Int): dynamic {
        var timeout: dynamic = null
        return js("function() { var args = arguments; var ctx = this; clearTimeout(timeout); timeout = setTimeout(function() { func.apply(ctx, args); }, wait); }")
    }
}
