package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import org.w3c.dom.HTMLInputElement
import org.w3c.dom.HTMLTextAreaElement
import kotlin.js.Promise

@JsExport
@JsName("adminShelters")
object AdminSheltersModule {
    var editingId: Int = 0

    fun loadShelters(): Promise<dynamic> {
        return ApiModule.fetch("/admin/shelters", js("({method: 'GET'})")).then<dynamic> { shelters ->
            renderShelters(shelters)
        }
    }

    private fun renderShelters(shelters: dynamic) {
        val container = window.document.getElementById("admin-shelters-container") ?: return
        container.innerHTML = ""
        val sheltersArray = if (shelters is Array<*>) shelters else js("([])")
        for (i in 0 until sheltersArray.length) {
            val s = sheltersArray[i]
            val div = window.document.createElement("div")
            div.className = "shelter-item"
            val h3 = window.document.createElement("h3")
            h3.textContent = s.asDynamic().name as? String
            val p = window.document.createElement("p")
            p.textContent = "${s.asDynamic().city}, ${s.asDynamic().state}"
            val editBtn = window.document.createElement("button")
            editBtn.textContent = "Edit"
            editBtn.addEventListener("click", { editShelter(s.asDynamic().id as Int) })
            val deleteBtn = window.document.createElement("button")
            deleteBtn.textContent = "Delete"
            deleteBtn.addEventListener("click", { deleteShelter(s.asDynamic().id as Int) })
            div.appendChild(h3)
            div.appendChild(p)
            div.appendChild(editBtn)
            div.appendChild(deleteBtn)
            container.appendChild(div)
        }
    }

    fun showMessage(msg: String, type: String) {
        val messageEl = window.document.getElementById("admin-shelter-message")
        if (messageEl != null) {
            messageEl.textContent = msg
            messageEl.asDynamic().className = "message $type"
        }
    }

    fun getFormData(): dynamic {
        val name = (window.document.getElementById("shelter-name") as? HTMLInputElement)?.value ?: ""
        val address = (window.document.getElementById("shelter-address") as? HTMLInputElement)?.value ?: ""
        val city = (window.document.getElementById("shelter-city") as? HTMLInputElement)?.value ?: ""
        val state = (window.document.getElementById("shelter-state") as? HTMLInputElement)?.value ?: ""
        val description = (window.document.getElementById("shelter-description") as? HTMLTextAreaElement)?.value ?: ""
        return js("({name: name, address: address, city: city, state: state, description: description})")
    }

    fun clearForm() {
        (window.document.getElementById("shelter-name") as? HTMLInputElement)?.value = ""
        (window.document.getElementById("shelter-address") as? HTMLInputElement)?.value = ""
        (window.document.getElementById("shelter-city") as? HTMLInputElement)?.value = ""
        (window.document.getElementById("shelter-state") as? HTMLInputElement)?.value = ""
        (window.document.getElementById("shelter-description") as? HTMLTextAreaElement)?.value = ""
        editingId = 0
    }

    fun cancelEdit() {
        clearForm()
        window.document.getElementById("admin-shelter-form")?.asDynamic()?.style?.display = "none"
    }

    fun editShelter(id: Int): Promise<dynamic> {
        return ApiModule.fetch("/admin/shelters/$id", js("({method: 'GET'})")).then<dynamic> { shelter ->
            editingId = id
            (window.document.getElementById("shelter-name") as? HTMLInputElement)?.value = shelter.asDynamic().name as? String ?: ""
            (window.document.getElementById("shelter-address") as? HTMLInputElement)?.value = shelter.asDynamic().address as? String ?: ""
            (window.document.getElementById("shelter-city") as? HTMLInputElement)?.value = shelter.asDynamic().city as? String ?: ""
            (window.document.getElementById("shelter-state") as? HTMLInputElement)?.value = shelter.asDynamic().state as? String ?: ""
            (window.document.getElementById("shelter-description") as? HTMLTextAreaElement)?.value = shelter.asDynamic().description as? String ?: ""
            window.document.getElementById("admin-shelter-form")?.asDynamic()?.style?.display = "block"
        }
    }

    fun deleteShelter(id: Int): Promise<dynamic> {
        return ApiModule.fetch("/admin/shelters/$id", js("({method: 'DELETE'})")).then<dynamic> {
            loadShelters()
            showMessage("Shelter deleted successfully", "success")
        }.catch<dynamic> { error ->
            showMessage("Failed to delete shelter: ${error.asDynamic().message as String}", "error")
        }
    }
}
