package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import org.w3c.dom.HTMLInputElement
import org.w3c.dom.HTMLTextAreaElement
import kotlin.js.Promise

@JsExport
@JsName("sterilizationLocations")
object SterilizationLocationsModule {

    fun loadCountries(): Promise<dynamic> {
        return ApiModule.fetch("/users/sterilization-location", js("({method: 'GET'})"))
            .catch<dynamic> { js("null") }
    }

    fun loadLocations(): Promise<dynamic> {
        return ApiModule.fetch("/admin/sterilization-locations", js("({method: 'GET'})")).then<dynamic> { locs ->
            renderLocations(locs)
        }
    }

    private fun renderLocations(locs: dynamic) {
        val container = window.document.getElementById("admin-sterilization-container") ?: return
        container.innerHTML = ""
        val locsArray = if (locs is Array<*>) locs else js("([])")
        for (i in 0 until locsArray.length) {
            val loc = locsArray[i]
            val div = window.document.createElement("div")
            div.className = "location-item"
            val h3 = window.document.createElement("h3")
            h3.textContent = loc.asDynamic().name as? String
            val p = window.document.createElement("p")
            p.textContent = loc.asDynamic().address as? String
            val editBtn = window.document.createElement("button")
            editBtn.textContent = "Edit"
            editBtn.addEventListener("click", { editLocation(loc.asDynamic().id as Int) })
            val deleteBtn = window.document.createElement("button")
            deleteBtn.textContent = "Delete"
            deleteBtn.addEventListener("click", { deleteLocation(loc.asDynamic().id as Int) })
            div.appendChild(h3)
            div.appendChild(p)
            div.appendChild(editBtn)
            div.appendChild(deleteBtn)
            container.appendChild(div)
        }
    }

    fun showForm() {
        window.document.getElementById("sterilization-form")?.asDynamic()?.style?.display = "block"
    }

    fun hideForm() {
        window.document.getElementById("sterilization-form")?.asDynamic()?.style?.display = "none"
        clearForm()
    }

    private fun clearForm() {
        (window.document.getElementById("location-name") as? HTMLInputElement)?.value = ""
        (window.document.getElementById("location-address") as? HTMLInputElement)?.value = ""
        (window.document.getElementById("location-city") as? HTMLInputElement)?.value = ""
        (window.document.getElementById("location-state") as? HTMLInputElement)?.value = ""
        (window.document.getElementById("location-phone") as? HTMLInputElement)?.value = ""
    }

    fun editLocation(id: Int): Promise<dynamic> {
        return ApiModule.fetch("/admin/sterilization-locations/$id", js("({method: 'GET'})")).then<dynamic> { loc ->
            showForm()
            (window.document.getElementById("location-name") as? HTMLInputElement)?.value = loc.asDynamic().name as? String ?: ""
            (window.document.getElementById("location-address") as? HTMLInputElement)?.value = loc.asDynamic().address as? String ?: ""
            (window.document.getElementById("location-city") as? HTMLInputElement)?.value = loc.asDynamic().city as? String ?: ""
            (window.document.getElementById("location-state") as? HTMLInputElement)?.value = loc.asDynamic().state as? String ?: ""
            (window.document.getElementById("location-phone") as? HTMLInputElement)?.value = loc.asDynamic().phone as? String ?: ""
        }
    }

    fun deleteLocation(id: Int): Promise<dynamic> {
        return ApiModule.fetch("/admin/sterilization-locations/$id", js("({method: 'DELETE'})")).then<dynamic> {
            loadLocations()
        }
    }
}
