package com.adoptu.frontend.utils

import com.adoptu.frontend.ApiModule

@Deprecated("Use com.adoptu.frontend.ApiModule instead", ReplaceWith("ApiModule", "com.adoptu.frontend.ApiModule"))
@JsExport
object ApiClient {
    var base: String
        get() = ApiModule.base
        set(value) { ApiModule.base = value }

    fun fetch(path: String, options: dynamic? = null): dynamic = ApiModule.fetch(path, options)
    fun me(): dynamic = ApiModule.me()
    fun logout(): dynamic = ApiModule.logout()
    fun getPets(type: Any? = null): dynamic = ApiModule.getPets(type as? String)
    fun getPet(id: String): dynamic = ApiModule.getPet(id.toInt())
    fun createPet(pet: dynamic): dynamic = ApiModule.createPet(pet)
    fun updatePet(id: String, pet: dynamic): dynamic = ApiModule.updatePet(id.toInt(), pet)
    fun deletePet(id: String): dynamic = ApiModule.deletePet(id.toInt())
    fun adoptPet(id: String, message: dynamic? = null): dynamic = ApiModule.adoptPet(id.toInt(), message as? String)
    fun addImage(petId: String, file: dynamic, isPrimary: Boolean = false): dynamic = ApiModule.addImage(petId.toInt(), file, isPrimary)
    fun removeImage(petId: String, imageId: String): dynamic = ApiModule.removeImage(petId.toInt(), imageId.toInt())
    fun setPrimaryImage(petId: String, imageId: String): dynamic = ApiModule.setPrimaryImage(petId.toInt(), imageId.toInt())
    fun getAdoptionRequests(petId: String): dynamic = ApiModule.getAdoptionRequests(petId.toInt())
    fun updateAdoptionRequest(requestId: String, status: String): dynamic = ApiModule.updateAdoptionRequest(requestId.toInt(), status)
    fun getMyAdoptionRequests(): dynamic = ApiModule.getMyAdoptionRequests()
    fun getPhotographers(): dynamic = ApiModule.getPhotographers()
    fun updateProfile(displayName: String): dynamic = ApiModule.updateProfile(displayName)
    fun updatePhotographerSettings(fee: dynamic?, currency: dynamic?, country: dynamic?, state: dynamic?): dynamic =
        ApiModule.updatePhotographerSettings((fee as? Number)?.toInt() ?: 0, currency as? String ?: "", country as? String ?: "", state as? String ?: "")
    fun createPhotographyRequest(photographerId: String, petId: String, message: dynamic? = null): dynamic =
        ApiModule.createPhotographyRequest(photographerId.toInt(), petId.toIntOrNull(), message as? String ?: "")
    fun createMultiplePhotographyRequests(photographerIds: Array<String>, petId: String, message: dynamic? = null): dynamic =
        ApiModule.createMultiplePhotographyRequests(photographerIds, petId.toIntOrNull(), message as? String ?: "")
    fun getPhotographyRequests(): dynamic = ApiModule.getPhotographyRequests()
    fun updatePhotographyRequest(requestId: String, status: dynamic? = null, scheduledDate: dynamic? = null): dynamic =
        ApiModule.updatePhotographyRequest(requestId.toInt(), status as? String, scheduledDate as? String)
    fun activateRescuer(activate: Boolean): dynamic = ApiModule.activateRescuer(activate)
    fun activatePhotographer(activate: Boolean): dynamic = ApiModule.activatePhotographer(activate)
    fun activateTemporalHome(activate: Boolean): dynamic = ApiModule.activateTemporalHome(activate)
    fun createTemporalHome(data: dynamic): dynamic = ApiModule.createTemporalHome(data)
    fun updateTemporalHome(data: dynamic): dynamic = ApiModule.updateTemporalHome(data)
    fun getTemporalHome(): dynamic = ApiModule.getTemporalHome()
    fun getTemporalHomeRequests(): dynamic = ApiModule.getTemporalHomeRequests()
    fun blockRescuer(rescuerId: String): dynamic = ApiModule.blockRescuer(rescuerId.toInt())
    fun updateLanguage(language: String): dynamic = ApiModule.updateLanguage(language)
    fun hasPassword(): dynamic = ApiModule.hasPassword()
    fun setPassword(encryptedPassword: String): dynamic = ApiModule.setPassword(encryptedPassword)
    fun changePassword(encryptedCurrentPassword: String, encryptedNewPassword: String): dynamic =
        ApiModule.changePassword(encryptedCurrentPassword, encryptedNewPassword)
    fun requestEmailChange(newEmail: String): dynamic = ApiModule.requestEmailChange(newEmail)
    fun requestMagicLink(encryptedData: String): dynamic = ApiModule.requestMagicLink(encryptedData)
    fun loginWithPassword(email: String, encryptedPassword: String): dynamic =
        ApiModule.loginWithPassword(email, encryptedPassword)
    fun forgotPassword(encryptedData: String): dynamic = ApiModule.forgotPassword(encryptedData)
    fun resetPassword(token: String, encryptedPassword: String): dynamic =
        ApiModule.resetPassword(token, encryptedPassword)
}
