package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import kotlinx.browser.window
import org.w3c.dom.HTMLInputElement
import org.w3c.dom.HTMLElement
import kotlin.js.Promise

@JsExport
@JsName("myPets")
object MyPetsModule {
    var editingId: Int = 0
    var previewFiles: dynamic = js("([])")

    fun load(): Promise<dynamic> {
        return ApiModule.getPets(null).then<dynamic> { pets ->
            renderPets(pets)
            loadAdoptionRequests(pets)
        }
    }

    private fun renderPets(pets: dynamic) {
        val container = window.document.getElementById("my-pets-container") ?: return
        container.innerHTML = ""
        val petsArray = if (pets is Array<*>) pets else js("([])")
        for (i in 0 until petsArray.length) {
            val pet = petsArray[i]
            val div = window.document.createElement("div")
            div.className = "pet-item"
            val h3 = window.document.createElement("h3")
            h3.textContent = pet.asDynamic().name as? String
            val p = window.document.createElement("p")
            p.textContent = "${pet.asDynamic().type} - ${pet.asDynamic().breed}"
            val editBtn = window.document.createElement("button")
            editBtn.textContent = "Edit"
            editBtn.addEventListener("click", { edit(pet.asDynamic().id as Int) })
            val delBtn = window.document.createElement("button")
            delBtn.textContent = "Delete"
            delBtn.addEventListener("click", { del(pet.asDynamic().id as Int) })
            div.appendChild(h3)
            div.appendChild(p)
            div.appendChild(editBtn)
            div.appendChild(delBtn)
            container.appendChild(div)
        }
    }

    fun loadAdoptionRequests(pets: dynamic): Promise<dynamic> {
        return ApiModule.getMyAdoptionRequests().then<dynamic> { requests ->
            renderAdoptionRequests(requests)
        }
    }

    private fun renderAdoptionRequests(requests: dynamic) {
        val container = window.document.getElementById("adoption-requests-container") ?: return
        container.innerHTML = ""
        val requestsArray = if (requests is Array<*>) requests else js("([])")
        for (i in 0 until requestsArray.length) {
            val req = requestsArray[i]
            val div = window.document.createElement("div")
            div.className = "adoption-request"
            val p1 = window.document.createElement("p")
            p1.textContent = "Request from: ${req.asDynamic().userName}"
            val p2 = window.document.createElement("p")
            p2.textContent = "Message: ${req.asDynamic().message}"
            val approveBtn = window.document.createElement("button")
            approveBtn.textContent = "Approve"
            approveBtn.addEventListener("click", { approveRequest(req.asDynamic().id as Int) })
            val rejectBtn = window.document.createElement("button")
            rejectBtn.textContent = "Reject"
            rejectBtn.addEventListener("click", { rejectRequest(req.asDynamic().id as Int) })
            div.appendChild(p1)
            div.appendChild(p2)
            div.appendChild(approveBtn)
            div.appendChild(rejectBtn)
            container.appendChild(div)
        }
    }

    fun edit(id: Int): Promise<dynamic> {
        editingId = id
        return ApiModule.getPet(id).then<dynamic> { pet ->
            fillForm(pet)
        }
    }

    fun del(id: Int): Promise<dynamic> {
        return ApiModule.deletePet(id).then<dynamic> { load() }
    }

    fun fillForm(pet: dynamic) {
        (window.document.getElementById("pet-name") as? HTMLInputElement)?.value = pet.asDynamic().name as? String ?: ""
        (window.document.getElementById("pet-type") as? HTMLElement)?.setAttribute("value", pet.asDynamic().type as? String ?: "")
        (window.document.getElementById("pet-breed") as? HTMLInputElement)?.value = pet.asDynamic().breed as? String ?: ""
        (window.document.getElementById("pet-age") as? HTMLInputElement)?.value = pet.asDynamic().age?.toString() ?: ""
        (window.document.getElementById("pet-description") as? HTMLElement)?.textContent = pet.asDynamic().description as? String ?: ""
    }

    fun handleFiles(files: dynamic) {
        previewFiles = js("Array.from(files)")
        updatePreviews()
    }

    fun updatePreviews() {
        val container = window.document.getElementById("image-previews") ?: return
        container.innerHTML = ""
        for (i in 0 until previewFiles.length) {
            val file = previewFiles[i]
            val reader = js("new FileReader()")
            reader.onload = { event: dynamic ->
                val img = window.document.createElement("img")
                img.asDynamic().src = event.asDynamic().target.asDynamic().result
                img.className = "preview-image"
                val index = i
                img.addEventListener("click", { removePreview(index) })
                container.appendChild(img)
            }
            reader.readAsDataURL(file)
        }
    }

    fun setPrimaryImage(index: Int): Promise<dynamic> {
        val imageId = (window.document.getElementById("image-id-$index") as? HTMLInputElement)?.value?.toIntOrNull() ?: 0
        return if (imageId > 0 && editingId > 0) {
            ApiModule.setPrimaryImage(editingId, imageId).then<dynamic> { load() }
        } else Promise.resolve(Unit)
    }

    fun removeExistingImage(index: Int): Promise<dynamic> {
        val imageId = (window.document.getElementById("image-id-$index") as? HTMLInputElement)?.value?.toIntOrNull() ?: 0
        return if (imageId > 0 && editingId > 0) {
            ApiModule.removeImage(editingId, imageId).then<dynamic> { load() }
        } else Promise.resolve(Unit)
    }

    fun removePreview(index: Int) {
        val newFiles = js("([])")
        for (i in 0 until previewFiles.length) {
            if (i != index) newFiles.push(previewFiles[i])
        }
        previewFiles = newFiles
        updatePreviews()
    }

    fun approveRequest(requestId: Int): Promise<dynamic> =
        ApiModule.updateAdoptionRequest(requestId, "approved").then<dynamic> { load() }

    fun rejectRequest(requestId: Int): Promise<dynamic> =
        ApiModule.updateAdoptionRequest(requestId, "rejected").then<dynamic> { load() }
}
