package com.adoptu.frontend.pages

import kotlinx.browser.window
import kotlin.js.Promise

@JsExport
@JsName("emailVerification")
object EmailVerificationModule {

    fun startCountdown(): dynamic {
        val countdownEl = window.document.getElementById("countdown")
        val resendBtn = window.document.getElementById("resend-btn")
        var seconds = 60

        if (resendBtn != null) {
            resendBtn.asDynamic().disabled = true
        }

        val intervalRef: dynamic = js("({value: null})")

        intervalRef.value = window.setInterval({
            seconds--
            if (countdownEl != null) {
                countdownEl.textContent = "You can resend in $seconds seconds"
            }
            if (seconds <= 0) {
                window.clearInterval(intervalRef.value)
                if (resendBtn != null) {
                    resendBtn.asDynamic().disabled = false
                }
                if (countdownEl != null) {
                    countdownEl.textContent = ""
                }
            }
        }, 1000)

        window.asDynamic()._countdownInterval = intervalRef.value
        return intervalRef.value
    }
}
