package com.adoptu.frontend.pages

import com.adoptu.frontend.*
import com.adoptu.frontend.i18n.I18nModule
import kotlinx.browser.window
import org.w3c.dom.HTMLButtonElement
import org.w3c.dom.HTMLInputElement
import org.w3c.dom.HTMLElement
import kotlin.js.Promise

@JsExport
@JsName("login")
object LoginModule {
    var pendingEmail: String = ""

    fun updateLangButton() = I18nModule.updateActiveLangOption()

    fun checkProfileCompletion(user: dynamic) = CommonModule.checkProfileCompletion(user)

    fun showResendButton() {
        val resendBtn = window.document.getElementById("resend-btn")
        if (resendBtn != null) {
            resendBtn.asDynamic().style.display = "block"
        }
    }

    fun init(): Promise<dynamic> {
        val loginBtn = window.document.getElementById("login-btn") as? HTMLButtonElement
        val resendBtn = window.document.getElementById("resend-btn") as? HTMLButtonElement
        val magicBtn = window.document.getElementById("magic-link-btn") as? HTMLButtonElement
        val passwordBtn = window.document.getElementById("password-login-btn") as? HTMLButtonElement

        loginBtn?.addEventListener("click", { handlePasskeyLogin() })
        resendBtn?.addEventListener("click", { handleResendVerification() })
        magicBtn?.addEventListener("click", { handleMagicLink() })
        passwordBtn?.addEventListener("click", { handlePasswordLogin() })

        handleHashChange()
        return Promise.resolve(Unit)
    }

    fun handleHashChange() {
        val hash = window.location.hash
        if (hash.startsWith("#verify=")) {
            val email = hash.substring(8)
            pendingEmail = email
            showResendButton()
            showMessage("passkey-message", "Please check your email ($email) to verify your account before logging in.")
        }
    }

    private fun handlePasskeyLogin() {
        WebAuthnModule.authenticate()
    }

    private fun handleResendVerification() {
        val email = pendingEmail
        if (email.isNotEmpty()) {
            showMessage("passkey-message", "Verification email resent to $email")
        }
    }

    fun passwordLogin(): Promise<dynamic> = handlePasswordLogin()
    fun magicLinkLogin(): Promise<dynamic> = handleMagicLink()

    private fun handlePasswordLogin(): Promise<dynamic> {
        val emailInput = window.document.getElementById("password-email") as? HTMLInputElement
        val passwordInput = window.document.getElementById("password-password") as? HTMLInputElement

        val email = emailInput?.value ?: ""
        val password = passwordInput?.value ?: ""

        if (email.isEmpty() || password.isEmpty()) {
            showMessage("password-login-message", "Please enter email and password")
            return Promise.resolve(Unit)
        }

        return getPublicKey().then<dynamic> { publicKey ->
            RsaCryptoModule.encrypt(password, publicKey)
        }.then<dynamic> { encryptedPassword ->
            ApiModule.loginWithPassword(email, encryptedPassword)
        }.then<dynamic> { result ->
            if (result.asDynamic().success == true) {
                window.location.href = "/"
            } else {
                showMessage("password-login-message", result.asDynamic().message as? String ?: "Login failed")
            }
        }.catch<dynamic> { error ->
            showMessage("password-login-message", "Login failed: ${error.asDynamic().message as String}")
        }
    }

    private fun handleMagicLink(): Promise<dynamic> {
        val emailInput = window.document.getElementById("magic-email") as? HTMLInputElement
        val email = emailInput?.value ?: ""

        if (email.isEmpty()) {
            showMessage("magic-link-message", "Please enter your email")
            return Promise.resolve(Unit)
        }

        return getPublicKey().then<dynamic> { publicKey ->
            RsaCryptoModule.encrypt(email, publicKey)
        }.then<dynamic> { encryptedData ->
            ApiModule.requestMagicLink(encryptedData)
        }.then<dynamic> {
            showMessage("magic-link-message", "Magic link sent to $email. Check your inbox.")
        }.catch<dynamic> { error ->
            showMessage("magic-link-message", "Failed to send magic link: ${error.asDynamic().message as String}")
        }
    }
}
